    "keyLearningPoints": [
      "Serotonin syndrome triad: altered mental status + autonomic dysfunction + NEUROMUSCULAR HYPERACTIVITY (clonus, myoclonus, hyperreflexia)",
      "Hunter Criteria: one serotonergic drug + (spontaneous clonus OR inducible clonus + agitation/diaphoresis OR ocular clonus + agitation/diaphoresis OR tremor + hyperreflexia OR hypertonia + temp >38\u00b0C + clonus)",
      "RAPID ONSET (hours) after serotonergic drug addition \u2014 this distinguishes from NMS (days)",
      "Stop ALL serotonergic agents immediately \u2014 most cases resolve within 24 hours after drug discontinuation",
      "Cyproheptadine (serotonin antagonist) is the specific antidote \u2014 12mg initial dose, then 2mg q2h",
      "Benzodiazepines for agitation \u2014 do NOT use physical restraints (increases temperature and risk of rhabdomyolysis)"
    ],
    "mustNotMiss": [
      "Neuroleptic Malignant Syndrome \u2014 LEAD-PIPE rigidity, NO clonus, develops over DAYS (not hours), antipsychotic trigger, CK typically >>10,000",
      "Malignant Hyperthermia (anesthesia-related trigger)",
      "Anticholinergic toxicity (dry, hot, red, mad \u2014 but NO clonus, dry skin vs diaphoresis in SS)",
      "Sympathomimetic intoxication (cocaine, amphetamines \u2014 similar but no clonus)",
      "Meningitis/Encephalitis (fever + AMS \u2014 LP if any doubt)",
      "Thyroid Storm (tachycardia, agitation, tremor, hyperthermia \u2014 check TSH)"
    ],
    "commonPitfalls": [
      "Confusing serotonin syndrome with NMS \u2014 the KEY differentiator is clonus (present in SS, absent in NMS)",
      "Not taking a thorough medication history \u2014 many drugs have serotonergic properties (tramadol, linezolid, triptans, MDMA, dextromethorphan, St. John's Wort)",
      "Not recognizing that TWO serotonergic drugs are needed \u2014 it's the COMBINATION or dose INCREASE that triggers SS",
      "Using physical restraints on an agitated patient \u2014 increases temperature and rhabdomyolysis risk, use benzodiazepines instead",
      "Not monitoring temperature \u2014 severe hyperthermia (>41\u00b0C) is the most common cause of SS mortality",
      "Missing the medication interaction \u2014 tramadol is often not recognized as serotonergic by prescribers"
    ],
