    "keyLearningPoints": [
      "Neutropenic fever = ANC <500 + single temp \u2265101\u00b0F (38.3\u00b0C) or sustained \u2265100.4\u00b0F (38.0\u00b0C) \u2014 this is an ONCOLOGIC EMERGENCY",
      "Empiric antibiotics within 60 MINUTES \u2014 cefepime or meropenem (anti-pseudomonal coverage mandatory)",
      "This patient has penicillin ANAPHYLAXIS \u2014 use meropenem (carbapenems are safe in >97% of penicillin-allergic patients) or aztreonam + vancomycin",
      "Neutropenic patients lack the ability to mount normal inflammatory responses \u2014 exam and labs may be FALSELY REASSURING",
      "CXR may be normal despite pneumonia, UA may lack pyuria despite UTI, abdomen may lack peritoneal signs despite intra-abdominal infection",
      "MASCC score helps risk-stratify: low-risk patients may receive outpatient oral antibiotics; high-risk patients require IV antibiotics and admission"
    ],
    "mustNotMiss": [
      "Typhlitis (neutropenic enterocolitis) \u2014 RLQ pain, fever, neutropenia = cecal inflammation, can perforate",
      "Perianal abscess (do NOT perform rectal exam in neutropenic patients \u2014 can seed bacteremia)",
      "Invasive fungal infection (if fever persists >4-7 days on antibiotics \u2014 add antifungal coverage)",
      "Central line infection (if applicable \u2014 must draw cultures through line AND peripherally)",
      "Pneumocystis pneumonia (if on chronic steroids or prolonged immunosuppression without prophylaxis)"
    ],
    "commonPitfalls": [
      "Delaying antibiotics \u2014 every hour of delay increases mortality in neutropenic sepsis",
      "Being reassured by a 'normal' exam \u2014 neutropenic patients have blunted inflammatory responses",
      "Not covering Pseudomonas \u2014 anti-pseudomonal beta-lactam is mandatory empiric coverage",
      "Performing rectal exam or placing rectal thermometer \u2014 risk of mucosal breach and bacteremia",
      "Checking ANC only once \u2014 must trend to know if patient is at nadir or recovering",
      "Withholding G-CSF because 'oncology hasn't ordered it' \u2014 discuss with oncologist but don't delay antibiotics"
    ],
