  "severe-allergic-reaction": {
    "id": "severe-allergic-reaction",
    "diagnosis": "Severe Allergic Reaction",
    "acuity": 2,
    "presentation": "Allergic",
    "category": "allergy",
    "chiefComplaint": "Urticaria/Angioedema/Dyspnea",
    "treatments": {
      "orders": [
        {
          "id": "epi-sar",
          "name": "Epinephrine 0.3mg IM anterolateral thigh",
          "group": "Critical",
          "critical": true,
          "correct": true,
          "phase": 1,
          "teaching": "FIRST-LINE for anaphylaxis/severe allergic reaction. IM mid-outer thigh. Repeat q5-15min. NO absolute contraindications.",
          "references": [
            {
              "source": "Anaphylaxis-StatPearls",
              "url": "https://www.ncbi.nlm.nih.gov/books/NBK482124/",
              "detail": "IM epinephrine first-line"
            }
          ]
        },
        {
          "id": "ivf-sar",
          "name": "NS 1-2L IV bolus",
          "group": "Resuscitation",
          "critical": true,
          "correct": true,
          "phase": 1,
          "teaching": "Distributive shock-massive vasodilation. May need 5-10L in severe anaphylaxis.",
          "references": [
            {
              "source": "Anaphylaxis-StatPearls",
              "url": "https://www.ncbi.nlm.nih.gov/books/NBK482124/",
              "detail": "IVF for distributive shock"
            }
          ]
        },
        {
          "id": "albuterol-sar",
          "name": "Albuterol 2.5mg neb",
          "group": "Bronchospasm",
          "critical": false,
          "correct": true,
          "phase": 1,
          "teaching": "For bronchospasm. Adjunct to epinephrine, not replacement.",
          "references": [
            {
              "source": "Anaphylaxis-StatPearls",
              "url": "https://www.ncbi.nlm.nih.gov/books/NBK482124/",
              "detail": "Albuterol adjunct"
            }
          ]
        },
        {
          "id": "steroid-sar",
          "name": "Methylprednisolone 125mg IV",
          "group": "Adjunctive",
          "critical": false,
          "correct": true,
          "phase": 1,
          "teaching": "Prevents biphasic reaction (up to 20% recurrence 4-8h later). NOT for acute treatment-onset too slow.",
          "references": [
            {
              "source": "Anaphylaxis-StatPearls",
              "url": "https://www.ncbi.nlm.nih.gov/books/NBK482124/",
              "detail": "Steroids for biphasic prevention"
            }
          ]
        },
        {
          "id": "h1h2-sar",
          "name": "Diphenhydramine 50mg IV + Famotidine 20mg IV",
          "group": "Adjunctive",
          "critical": false,
          "correct": true,
          "phase": 1,
          "teaching": "H1+H2 blockers for urticaria/itching. Adjunct only-do NOT substitute for epinephrine.",
          "references": [
            {
              "source": "Anaphylaxis-StatPearls",
              "url": "https://www.ncbi.nlm.nih.gov/books/NBK482124/",
              "detail": "H1+H2 adjunctive"
            }
          ]
        },
        {
          "id": "tryptase-sar",
          "name": "Serum tryptase level",
          "group": "Diagnostics",
          "critical": false,
          "correct": true,
          "phase": 1,
          "teaching": "Elevated tryptase confirms mast cell activation. Draw within 1-2h of onset. Normal tryptase does NOT exclude anaphylaxis.",
          "references": [
            {
              "source": "Anaphylaxis-StatPearls",
              "url": "https://www.ncbi.nlm.nih.gov/books/NBK482124/",
              "detail": "Tryptase within 1-2h"
            }
          ]
        },
        {
          "id": "epi-iv-sar",
          "name": "Epinephrine IV push",
          "group": "Treatment",
          "critical": false,
          "correct": false,
          "phase": 1,
          "teaching": "IV push epinephrine is DANGEROUS outside cardiac arrest. Causes hypertensive crisis, arrhythmias, MI. Use IM or IV DRIP if refractory.",
          "references": [
            {
              "source": "Anaphylaxis-StatPearls",
              "url": "https://www.ncbi.nlm.nih.gov/books/NBK482124/",
              "detail": "IV push dangerous"
            }
          ]
        }
      ],
      "phases": [
        {
          "id": "initial",
          "label": "Presentation",
          "auto": true,
          "vitals": {
            "BP": "86/52",
            "HR": "126",
            "RR": "28",
            "Temp": "98.6F",
            "SpO2": "89%"
          },
          "ecg": "Sinus tachycardia",
          "labHighlights": {
            "Tryptase": "Pending"
          },
          "examNote": "Diffuse urticaria, lip/tongue angioedema, stridor, diffuse wheezing. Ate shrimp 20min ago. Prior allergic reactions. Hives spreading rapidly."
        },
        {
          "id": "treated",
          "label": "Epinephrine+IVF",
          "requires": [
            "epi-sar",
            "ivf-sar"
          ],
          "vitals": {
            "BP": "108/68",
            "HR": "96",
            "RR": "20",
            "Temp": "98.6F",
            "SpO2": "96%"
          },
          "ecg": "NSR",
          "labHighlights": {
            "Tryptase": "24.6(elevated)"
          },
          "examNote": "Urticaria fading. Angioedema improving. Wheezing resolved. BP responding. Required 2 doses IM epi.",
          "aiPatientUpdate": "I can breathe better. The hives are going down.",
          "teaching": "Anaphylaxis confirmed (2+ systems: skin+respiratory+cardiovascular). Observe 4-6h minimum (biphasic risk). Discharge with: (1) EpiPen Rx + training (2) Allergist referral (3) Anaphylaxis action plan (4) Allergy testing for specific trigger."
        }
      ],
      "pitfallEvents": [
        {
          "trigger": "epi-iv-sar",
          "event": "arrhythmia",
          "message": "IV push epi caused hypertensive crisis+ventricular tachycardia. IV push only for cardiac arrest.",
          "recovery": "IV amiodarone if VT sustained. IM epi is correct route.",
          "vitals": {
            "BP": "220/130",
            "HR": "180"
          }
        }
      ]
    },
    "keyLearningPoints": [
      "Epinephrine IM is ALWAYS first-line. No absolute contraindications",
      "Biphasic reactions in up to 20%-observe 4-6h minimum",
      "Draw tryptase within 1-2h (normal doesnt exclude anaphylaxis)",
      "IV push epi=dangerous outside cardiac arrest. Use IM or IV drip",
      "H1+H2+steroids are ADJUNCTS-never substitutes for epi",
      "Discharge with EpiPen+allergist referral+action plan"
    ],
    "mustNotMiss": [
      "Biphasic anaphylaxis (4-8h after initial, can be MORE severe)",
      "Refractory anaphylaxis (>2 doses epi-consider epi drip+glucagon if on beta-blocker)",
      "Anaphylaxis vs vasovagal (both cause hypotension-vasovagal has bradycardia, anaphylaxis has tachycardia)"
    ],
    "commonPitfalls": [
      "Antihistamines instead of epinephrine",
      "IV push epi in non-arrest",
      "Short observation (<4h)",
      "No EpiPen at discharge",
      "Not referring to allergist"
    ]
  },
